
const tt = require("typescript-definition-tester");

if (!global.main) {
    const pack = require('../../package.json');
    global.main = require('../../' + pack.main);
}

it('Project type definitions work', function(done) {
    this.timeout(5000);
    tt.compileDirectory(
        __dirname + '/dts',
        (fileName) => fileName.indexOf('.ts') > -1,
        () => done()
    );
});
